dbutils.widgets.text("p_data_source","")
v_data_source = dbutils.widgets.get("p_data_source")

# COMMAND ----------

dbutils.widgets.text("p_file_date",'2024-02-24')
v_file_date = dbutils.widgets.get("p_file_date")

# COMMAND ----------

print(v_file_date)

# COMMAND ----------

from pyspark.sql.types import StructType, StructField, StringType, IntegerType, DoubleType

# COMMAND ----------

circuits_schema = StructType(fields=[StructField("circuitId", IntegerType(), False),
                                       StructField("circuitRef", StringType(), True),
                                       StructField("name", StringType(), True),
                                       StructField("location", StringType(), True),
                                       StructField("country", StringType(), True),
                                       StructField("lat", DoubleType(), True),
                                       StructField("lng", DoubleType(), True),
                                       StructField("alt", IntegerType(), True),
                                       StructField("url", StringType(), True)])

# COMMAND ----------

circuits_df=spark.read\
    .option("header", True)\
    .schema(circuits_schema)\
    .csv(f"{raw_folder_path}/{v_file_date}/circuits.csv")

# COMMAND ----------

from pyspark.sql.functions import col,lit

# COMMAND ----------

circuits_selected_df=circuits_df.select(col("circuitId"),col("circuitRef"),col("name"),col("location"),col("country"),col("lat"),col("lng"),col("alt"))

# COMMAND ----------

circuits_renamed_columns=circuits_selected_df.withColumnRenamed("circuitId","circuit_id")\
    .withColumnRenamed("circuitRef","circuit_ref") \
    .withColumnRenamed("lat","latitude") \
    .withColumnRenamed("lng","longitude") \
    .withColumnRenamed("alt","altitude")\
    .withColumn("data_source", lit(v_data_source))\
    .withColumn("file_date", lit(v_file_date))


# COMMAND ----------

# MAGIC %md 
# MAGIC ###Add ingestion date to the dataframe 

# COMMAND ----------

from pyspark.sql.functions import current_timestamp


# COMMAND ----------

circuits_final_df = add_ingestion_date(circuits_renamed_columns)

# COMMAND ----------

# MAGIC %md
# MAGIC ###Write data to data lake as parquet 

# COMMAND ----------

circuits_final_df.write.format("Delta").mode("overwrite").saveAsTable("f1_processed.circuits")

# COMMAND ----------

circuits_final_df.write.format("Delta").mode("overwrite").save(f"{processed_folder_path}/circuits")

# COMMAND ----------

# MAGIC %sql
# MAGIC select * from f1_processed.circuits

# COMMAND ----------

dbutils.notebook.exit("success")


